import type { ComponentProps } from 'react';
import { Tooltip as TooltipPrimitive } from '@base-ui/react/tooltip';
import { PopupArrowIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Tooltip.module.css';

type TooltipPositionerProps = Pick<
  TooltipPrimitive.Positioner.Props,
  | 'side'
  | 'sideOffset'
  | 'align'
  | 'alignOffset'
  | 'arrowPadding'
  | 'collisionAvoidance'
  | 'collisionBoundary'
  | 'collisionPadding'
>;

type TooltipContentProps = TooltipPrimitive.Popup.Props &
  TooltipPositionerProps & {
    showArrow?: boolean;
  };

const TOOLTIP_CONTENT_SIDE_OFFSET = 8;

const Tooltip = TooltipPrimitive.Root;
const TooltipProvider = TooltipPrimitive.Provider;
const createTooltipHandle = TooltipPrimitive.createHandle;

function TooltipTrigger<Payload = unknown>({
  className,
  render,
  ...props
}: TooltipPrimitive.Trigger.Props<Payload>) {
  const triggerClassName = render ? className : mergeClassName(className, styles.trigger);

  return (
    <TooltipPrimitive.Trigger
      data-slot="tooltip-trigger"
      render={render}
      className={triggerClassName}
      {...props}
    />
  );
}

function TooltipPortal({ className, ...props }: TooltipPrimitive.Portal.Props) {
  return <TooltipPrimitive.Portal data-slot="tooltip-portal" className={className} {...props} />;
}

function TooltipPositioner({ className, ...props }: TooltipPrimitive.Positioner.Props) {
  return (
    <TooltipPrimitive.Positioner
      data-slot="tooltip-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function TooltipPopup({ className, ...props }: TooltipPrimitive.Popup.Props) {
  return (
    <TooltipPrimitive.Popup
      data-slot="tooltip-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function TooltipArrow({ className, children, ...props }: TooltipPrimitive.Arrow.Props) {
  return (
    <TooltipPrimitive.Arrow
      data-slot="tooltip-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? <ArrowSvg className={styles.arrowSvg} />}
    </TooltipPrimitive.Arrow>
  );
}

function TooltipViewport({ className, ...props }: TooltipPrimitive.Viewport.Props) {
  return (
    <TooltipPrimitive.Viewport
      data-slot="tooltip-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function TooltipContent({
  className,
  showArrow = false,
  side,
  sideOffset = TOOLTIP_CONTENT_SIDE_OFFSET,
  align,
  alignOffset,
  arrowPadding,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  children,
  ...popupProps
}: TooltipContentProps) {
  return (
    <TooltipPortal>
      <TooltipPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <TooltipPopup className={className} {...popupProps}>
          {showArrow ? <TooltipArrow /> : null}
          <TooltipViewport>{children}</TooltipViewport>
        </TooltipPopup>
      </TooltipPositioner>
    </TooltipPortal>
  );
}

function ArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.arrowFill}
      outerStrokeClassName={styles.arrowOuterStroke}
      innerStrokeClassName={styles.arrowInnerStroke}
      {...props}
    />
  );
}

export {
  Tooltip,
  TooltipProvider,
  createTooltipHandle,
  TooltipTrigger,
  TooltipPortal,
  TooltipPositioner,
  TooltipPopup,
  TooltipArrow,
  TooltipViewport,
  TooltipContent,
};

@layer ui.components {
  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--tooltip-trigger-height, var(--size-lg));
    margin: 0;
    padding: var(--tooltip-trigger-padding-y, 0.5rem) var(--tooltip-trigger-padding-x, 0.875rem);
    border: var(--tooltip-trigger-border-width, var(--border-width-sm)) solid
      var(--tooltip-trigger-border-color, var(--color-border));
    border-radius: var(--tooltip-trigger-radius, var(--radius-md));
    background-color: var(--tooltip-trigger-bg, var(--color-background));
    color: var(--tooltip-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--tooltip-trigger-font-size, var(--text-sm));
    line-height: var(--tooltip-trigger-line-height, var(--line-height-text-sm));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--tooltip-transition, var(--transition-default)),
      border-color var(--tooltip-transition, var(--transition-default)),
      color var(--tooltip-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--tooltip-trigger-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-popup-open] {
      background-color: var(
        --tooltip-trigger-bg-active,
        var(--tooltip-trigger-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(--tooltip-focus-ring-width, var(--border-width-sm)) solid
        var(--tooltip-focus-ring-color, var(--color-ring));
      outline-offset: var(--tooltip-focus-ring-offset, -1px);
    }

    &[data-trigger-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--tooltip-disabled-opacity, var(--opacity-disabled));
    }
  }

  .positioner {
    z-index: var(--z-popup);
    width: var(--positioner-width);
    height: var(--positioner-height);
    max-width: var(--available-width);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    width: var(--popup-width, var(--tooltip-width, max-content));
    height: var(--popup-height, auto);
    max-width: min(var(--tooltip-max-width, 20rem), var(--available-width));
    max-height: min(var(--tooltip-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--tooltip-padding-y, 0.25rem) var(--tooltip-padding-x, 0.5rem);
    border: 0;
    border-radius: var(--tooltip-radius, var(--radius-md));
    background-color: var(--tooltip-bg, var(--color-popover));
    color: var(--tooltip-color, var(--color-popover-foreground));
    outline: var(--tooltip-border-width, var(--border-width-sm)) solid
      var(--tooltip-border-color, var(--color-border));
    box-shadow: var(--tooltip-shadow, var(--shadow-lg));
    font-size: var(--tooltip-font-size, var(--text-sm));
    line-height: var(--tooltip-line-height, var(--line-height-text-sm));
    text-align: center;
    transform-origin: var(--transform-origin);
    transition:
      transform var(--tooltip-transition, 150ms),
      opacity var(--tooltip-transition, 150ms);

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--tooltip-scale, var(--scale-popup)));
    }

    &[data-instant] {
      transition: none;
    }
  }

  .arrow {
    display: flex;
    color: var(--tooltip-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--tooltip-arrow-size, 8px) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--tooltip-arrow-size, 8px) * -1);
    }

    &[data-side='left'] {
      right: calc(var(--tooltip-arrow-inline-offset, 13px) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--tooltip-arrow-inline-offset, 13px) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--tooltip-arrow-width, 1.25rem);
    height: var(--tooltip-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(--tooltip-arrow-stroke-color, var(--tooltip-border-color, var(--color-border)));
  }

  .arrowInnerStroke {
    fill: var(--tooltip-bg, var(--color-popover));
  }

  .viewport {
    position: relative;
    width: 100%;
    height: 100%;
    overflow: hidden;

    &[data-transitioning] {
      min-width: var(--popup-width);
      min-height: var(--popup-height);
    }

    & > [data-current],
    & > [data-previous] {
      transition:
        transform var(--tooltip-content-transition, 150ms),
        opacity var(--tooltip-content-transition, 150ms);
    }

    & > [data-previous] {
      position: absolute;
      inset: 0;
      width: var(--popup-width);
      opacity: 0;
    }
  }
}
